blocks.body:
{
    "level": "A2–B2",
    "intro": "W tym temacie zebraliśmy <strong>najczęstsze błędy</strong> podczas używania strony biernej oraz praktyczne wskazówki, jak ich unikać. Uczenie się na błędach to najlepszy sposób, aby ich nie powtarzać!",
    "rules": [
        {
            "label": "Bądź + V3",
            "color": "emerald",
            "text": "Nie zapomnij o <strong>czasowniku be</strong> i <strong>V3 (imiesłów bierny)</strong>:",
            "example": "The letter is written. ✅ (не: The letter written. ❌)"
        },
        {
            "label": "V3 ≠ V2",
            "color": "rose",
            "text": "Użyj <strong>V3</strong>, a nie V2:",
            "example": "The window was broken. ✅ (не: was broke. ❌)"
        },
        {
            "label": "Bez robienia/robienia",
            "color": "blue",
            "text": "W <strong>pytaniach nie używaj do/does/did</strong>:",
            "example": "Is the letter written? ✅ (не: Does the letter is written? ❌)"
        }
    ]
}

{
    "title": "1. Błędy z czasownikiem BE",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie czasownika być.",
            "wrong": "The letter written yesterday.",
            "right": "✅ The letter was written yesterday."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Niepoprawna forma be (is/are).",
            "wrong": "The letters is sent every day.",
            "right": "✅ The letters are sent every day."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Niepoprawna forma bycia (był/był).",
            "wrong": "The windows was broken.",
            "right": "✅ The windows were broken."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Skip był w Perfect.",
            "wrong": "The work has done.",
            "right": "✅ The work has been done."
        }
    ]
}

{
    "title": "2. Błędy z imiesłowem czasu przeszłego (V3)",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Używanie V1 (bezokolicznik) zamiast V3.",
            "wrong": "English is speak here.",
            "right": "✅ English is spoken here."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Używanie V2 (past simple) zamiast V3.",
            "wrong": "The window was broke.",
            "right": "✅ The window was broken."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pomieszanie czasowników nieregularnych.",
            "wrong": "The book was writed by him.",
            "right": "✅ The book was written by him."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Używanie -ing zamiast V3.",
            "wrong": "The letter is writing now.",
            "right": "✅ The letter is being written now."
        }
    ]
}

{
    "title": "3. Błędy w pytaniach",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Używanie „do/does/did” w pytaniach.",
            "wrong": "Does the letter is written?",
            "right": "✅ Is the letter written?"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Nieprawidłowa kolejność słów.",
            "wrong": "The letter is written?",
            "right": "✅ Is the letter written?"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Błąd w pytaniach typu „wh”.",
            "wrong": "Where the book was found?",
            "right": "✅ Where was the book found?"
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Nieprawidłowa krótka odpowiedź.",
            "wrong": "Was the work done? — Yes, it done.",
            "right": "✅ Was the work done? — Yes, it was."
        }
    ]
}

{
    "title": "4. Błędy w zastrzeżeniach",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie lub nieprawidłowa lokalizacja.",
            "wrong": "The letter is not write.",
            "right": "✅ The letter is not written."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie nie/nie.",
            "wrong": "The work doesn't finished.",
            "right": "✅ The work isn't finished."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Niepoprawna forma nie.",
            "wrong": "The letter is no written.",
            "right": "✅ The letter is not written."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Błąd w Perfectu.",
            "wrong": "The work hasn't done.",
            "right": "✅ The work hasn't been done."
        }
    ]
}

{
    "title": "5. Błędy z by i with",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Używanie z dla executora.",
            "wrong": "The book was written with Shakespeare.",
            "right": "✅ The book was written by Shakespeare."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Używanie jako narzędzia.",
            "wrong": "The letter was written by a pen.",
            "right": "✅ The letter was written with a pen."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Nadmiarowy przez + agenta.",
            "wrong": "My car was stolen by someone.",
            "right": "✅ My car was stolen."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Nieprawidłowa lokalizacja wg.",
            "wrong": "By the team the report was prepared.",
            "right": "✅ The report was prepared by the team."
        }
    ]
}

{
    "title": "6. Prawidłowe przykłady użycia",
    "sections": [
        {
            "label": "Czas teraźniejszy prosty pasywny",
            "color": "emerald",
            "description": "<strong>jestem/jest/jestem + V3</strong>:",
            "examples": [
                {
                    "en": "English is spoken in many countries.",
                    "ua": "W wielu krajach mówi się po angielsku."
                },
                {
                    "en": "The office is cleaned every day.",
                    "ua": "Biuro sprzątane jest codziennie."
                },
                {
                    "en": "Cars are made in Germany.",
                    "ua": "Maszyny produkowane są w Niemczech."
                }
            ]
        },
        {
            "label": "Czas przeszły prosty bierny",
            "color": "blue",
            "description": "<strong>był/był + V3</strong>:",
            "examples": [
                {
                    "en": "The letter was sent yesterday.",
                    "ua": "List został wysłany wczoraj."
                },
                {
                    "en": "The house was built in 1990.",
                    "ua": "Dom został wybudowany w 1990 roku."
                },
                {
                    "en": "The windows were broken during the storm.",
                    "ua": "Podczas wichury wybito szyby."
                }
            ]
        },
        {
            "label": "Czas teraźniejszy idealny pasywny",
            "color": "amber",
            "description": "<strong>był/był + V3</strong>:",
            "examples": [
                {
                    "en": "The work has been completed.",
                    "ua": "Praca jest ukończona."
                },
                {
                    "en": "All tickets have been sold.",
                    "ua": "Wszystkie bilety zostały sprzedane."
                },
                {
                    "en": "The report has been submitted.",
                    "ua": "Raport przesłany."
                }
            ]
        },
        {
            "label": "Modalne pasywne",
            "color": "rose",
            "description": "<strong>modalne + być + V3</strong>:",
            "examples": [
                {
                    "en": "The task must be done today.",
                    "ua": "Zadanie ma zostać zrealizowane dzisiaj."
                },
                {
                    "en": "This problem can be solved.",
                    "ua": "Ten problem można rozwiązać."
                },
                {
                    "en": "The report should be checked carefully.",
                    "ua": "Należy dokładnie sprawdzić raport."
                }
            ]
        }
    ]
}

{
    "title": "7. Prawidłowa konwersja Aktywny → Pasywny",
    "intro": "Krok po kroku przekształcanie zdań czynnych w bierne:",
    "rows": [
        {
            "en": "Active: Tom writes letters.",
            "ua": "Tomek pisze na listę.",
            "note": "→ Passive: Letters are written by Tom."
        },
        {
            "en": "Active: She cleaned the room.",
            "ua": "Posprzątała pokój.",
            "note": "→ Passive: The room was cleaned."
        },
        {
            "en": "Active: They have finished the project.",
            "ua": "Ukończyli projekt.",
            "note": "→ Passive: The project has been finished."
        },
        {
            "en": "Active: Someone must do this work.",
            "ua": "Ktoś musi wykonać tę pracę.",
            "note": "→ Passive: This work must be done."
        }
    ],
    "warning": "📌 Przedmiot zdania czynnego → Podmiot bierny. Czasownik → być + V3."
}

{
    "title": "8. Lista kontrolna do sprawdzania zobowiązań",
    "intro": "Sprawdź swoje zdanie pod kątem następujących punktów:",
    "items": [
        {
            "label": "✓ 1",
            "title": "Czy istnieje czasownik BE?",
            "subtitle": "jestem/jest/jestem/byłem/byłem/byłem/byłem"
        },
        {
            "label": "✓ 2",
            "title": "Czy poprawna forma BE jest na czas?",
            "subtitle": "Obecny: jest/są; Przeszłość: był/był"
        },
        {
            "label": "✓ 3",
            "title": "Czy używany jest V3 (imiesłów bierny)?",
            "subtitle": "napisane, złamane, zrobione, zrobione"
        },
        {
            "label": "✓ 4",
            "title": "Czy formularz V3 jest poprawny?",
            "subtitle": "zepsuty (nie zepsuty), napisany (nie napisany)"
        },
        {
            "label": "✓ 5",
            "title": "Czy w pytaniach nie ma „zrób/zrób”?",
            "subtitle": "Czy to zrobione? (не: Czy to już zrobione?)"
        },
        {
            "label": "✓ 6",
            "title": "Czy przez/z jest poprawne?",
            "subtitle": "przez + agenta; z + instrumentem"
        }
    ]
}
